// Option 2: Register from assembly
builder.WithResourcesFromAssembly(
    resourceAssembly: Assembly.GetExecutingAssembly());

// Option 3: Register pre-built resource instances
builder.WithResources(new[] { resource1, resource2 });

// Option 4: Register resource types
builder.WithResources(new[] { typeof(MyResourceClass) });
```

#### Method Signatures:

```csharp
// Generic registration
