public class Calculator
{
    [McpServerTool(Description = "Add two numbers")]
    public int Add(int a, int b) => a + b;
}

// Define resources
[McpServerResourceType]
public class FileStore
{
    [McpServerResource(Uri = "resource://config")]
    public string GetConfig() => "Configuration data";

    [McpServerResource(Uri = "resource://files/{filename}")]
    public string GetFile(string filename) => $"Content of {filename}";
}

// Register MCP server
builder.Services
    .AddMcpServer()
    .WithTools<Calculator>()
    .WithResources<FileStore>()
    .WithHttpTransport(opts =>
    {
        opts.ConfigureSessionOptions = async (context, options) =>
        {
            // Per-session configuration
        };
    })
    .AddAuthorizationFilters();

var app = builder.Build();
app.MapMcp("/mcp");
app.Run();
```

---

This covers all the essential APIs needed to build a fully functional MCP HTTP server in ASP.NET Core with tools and resources.

