using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer.Tools;

[McpServerToolType]
public class EchoTools
{
    [McpServerTool(Name = "echo"), Description("Echoes the input message back to the caller.")]
    public string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "reverse"), Description("Reverses the input string.")]
    public string Reverse(string text)
    {
        var chars = text.ToCharArray();
        Array.Reverse(chars);
        return new string(chars);
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    /// <summary>
    /// A fixed resource that returns the current application configuration.
    /// Clients discover this via resources/list since the URI has no template parameters.
    /// </summary>
    [McpServerResource(
        Uri = "config://app/settings",
        Name = "App Settings",
        Description = "Returns current application configuration.",
        MimeType = "application/json")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { EnableLogging = true, EnableMetrics = false }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    /// <summary>
    /// A resource template that returns feature-flag status by name.
    /// Clients discover this via resources/templates/list and call it with a concrete URI
    /// like "config://app/features/dark-mode".
    /// </summary>
    [McpServerResource(
        Uri = "config://app/features/{featureName}",
        Name = "Feature Flag",
        Description = "Returns the status of a feature flag by name.",
        MimeType = "application/json")]
    public static string GetFeatureFlag(string featureName)
    {
        var knownFlags = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
        {
            ["dark-mode"] = true,
            ["beta-api"] = false,
            ["notifications"] = true
        };

        var flag = new
        {
            Name = featureName,
            Enabled = knownFlags.TryGetValue(featureName, out var enabled) && enabled,
            Known = knownFlags.ContainsKey(featureName)
        };

        return JsonSerializer.Serialize(flag, JsonOptions);
    }
}

